    // --- Voice Recording Functions ---


    const startRecording = () => {
        setIsRecording(true);
    };

    const formatVoiceTime = (seconds) => {
        const mins = Math.floor(seconds / 60);
        const secs = Math.floor(seconds % 60);
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    const audioInstanceRef = useRef(null);

    const handlePlayAudio = async (msg, startTime = 0) => {
        const audioUrlBase = msg.file_path || (typeof msg.content === 'string' && msg.content.includes('/uploads/') ? msg.content : null);
        if (!audioUrlBase) return;

        // Senders can now play view-once messages they sent
        // No longer returning early for isMeMsg(msg)


        // If view-once and already opened, stop
        const isSelfPlayed = selfPlayedMsgs.has(String(msg._id));
        if (msg.is_view_once && (msg.is_viewed || isSelfPlayed)) {
            setSnackbar({ message: "This message has already been played.", type: 'info', variant: 'system' });
            return;
        }

        // If clicking the same message that's already playing, and NOT seeking, stop it
        if (String(playingAudioId) === String(msg._id || msg.id) && startTime === 0) {
            if (audioInstanceRef.current) {
                audioInstanceRef.current.pause();
                audioInstanceRef.current = null;
            }
            setPlayingAudioId(null);
            return;
        }

        // Stop any currently playing audio
        if (audioInstanceRef.current) {
            audioInstanceRef.current.pause();
            audioInstanceRef.current = null;
        }

        // Handle URL formatting (Relative vs Absolute)
        let url = msg.file_path;
        if (!url && typeof msg.content === 'string' && msg.content.includes('/uploads/')) {
            url = msg.content;
        }
        // Strip any backend URLs pointing to port 3000 or /uploads/ so Vite proxy uses HTTPS
        if (url && url.startsWith('http')) {
            try {
                const parsed = new URL(url);
                if (parsed.port === '3000' || parsed.pathname.startsWith('/uploads/')) {
                    url = parsed.pathname + parsed.search;
                }
            } catch (e) { }
        }

        if (url && !url.startsWith('http') && !url.startsWith('blob:') && !url.startsWith('data:')) {
            // Use the base API URL or window origin since we have proxy
            url = `${window.location.protocol}//${window.location.host}${url.startsWith('/') ? '' : '/'}${url}`;
        }

        const audio = new Audio(url);
        audioInstanceRef.current = audio;
        // Always reset speed to 1x for new audio
        setPlaybackSpeed(1);
        setViewOncePlaybackSpeed(1);
        audio.playbackRate = 1;
        const currentMsgId = String(msg._id || msg.id); // Force string for comparison
        setPlayingAudioId(currentMsgId);
        setViewOnceElapsed(startTime);

        audio.onloadedmetadata = () => {
            if (startTime > 0) {
                audio.currentTime = startTime;
            }
        };

        audio.ontimeupdate = () => {
            setViewOnceElapsed(audio.currentTime);
        };

        // Remove immediate markViewed - we do it on end or close

        audio.onended = () => {
            setPlaybackSpeed(1);
            setViewOncePlaybackSpeed(1);
            if (msg.is_view_once) {
                if (!isMeMsg(msg)) {
                    markMessageViewed(msg._id);
                } else {
                    markSelfPlayed(msg._id);
                }
            }
            setPlayingAudioId(null);
            audioInstanceRef.current = null;
            setActiveViewOnceMsg(null);
            setViewOnceElapsed(0);
        };

        audio.onerror = (e) => {
            console.error("Audio playback error:", e);
            setPlayingAudioId(null);
            audioInstanceRef.current = null;
            setActiveViewOnceMsg(null);
            setSnackbar({ message: "Error playing audio.", type: 'error' });
        };

        if (msg.is_view_once) {
            setActiveViewOnceMsg(msg);
        }

        try {
            await audio.play();
        } catch (err) {
            console.error("Audio play failed:", err);
            setPlayingAudioId(null);
            audioInstanceRef.current = null;
        }
    };

    const togglePlaybackSpeed = (e) => {
        if (e) e.stopPropagation();

        // Prioritize updating the audio element's playbackRate first for instant response
        const currentAudio = audioInstanceRef.current;

        if (activeViewOnceMsg) {
            const nextSpeed = viewOncePlaybackSpeed === 1 ? 1.5 : (viewOncePlaybackSpeed === 1.5 ? 2 : 1);
            if (currentAudio) {
                currentAudio.playbackRate = nextSpeed;
            }
            setViewOncePlaybackSpeed(nextSpeed);
        } else {
            const nextSpeed = playbackSpeed === 1 ? 1.5 : (playbackSpeed === 1.5 ? 2 : 1);
            if (currentAudio) {
                currentAudio.playbackRate = nextSpeed;
            }
            setPlaybackSpeed(nextSpeed);
        }
    };

    const markMessageViewed = async (msgId) => {
        try {
            const token = localStorage.getItem('token');
            await axios.post(`/api/chat/message/${msgId}/viewed`, {}, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            // Update local state
            setMessages(prev => prev.map(m => String(m._id) === String(msgId) ? { ...m, is_viewed: true } : m));
            setGroupMessages(prev => prev.map(m => String(m._id) === String(msgId) ? { ...m, is_viewed: true } : m));
        } catch (err) {
            console.error("Mark viewed failed", err);
        }
    };





    const handleFileSelect = (e) => {
        if (e.target.files && e.target.files[0]) {
            const selectedFile = e.target.files[0];
            const extension = selectedFile.name.split('.').pop().toLowerCase();

            let allowedExtensions;
            if (attachmentTypeRef.current === 'document') {
                allowedExtensions = ['doc', 'docx', 'pdf', 'xls', 'xlsx'];
            } else if (attachmentTypeRef.current === 'media') {
                allowedExtensions = ['jpg', 'jpeg', 'png', 'mp4', 'avi', 'mkv', 'mov', 'webm'];
            } else {
                allowedExtensions = ['jpg', 'jpeg', 'png', 'doc', 'docx', 'pdf', 'xls', 'xlsx', 'mp4', 'avi', 'mkv', 'mov', 'webm'];
            }

            if (allowedExtensions.includes(extension)) {
                if (selectedFile.size > 1073741824) { // 1GB
                    setSnackbar({ message: 'File must be less than 1GB', type: 'error', variant: 'system' });
                    e.target.value = '';
                } else {
                    setFile(selectedFile);
                }
            } else {
                setSnackbar({ message: 'Unsupported file format.', type: 'error', variant: 'system' });
                e.target.value = ''; // Reset input
            }

            // reset to all after selection attempt
            attachmentTypeRef.current = 'all';
            if (fileInputRef.current) {
                fileInputRef.current.accept = ".jpg,.jpeg,.png,.doc,.docx,.pdf,.xls,.xlsx,.mp4,.avi,.mkv,.mov,.webm,video/*,image/*";
            }
        }
    };


    const handleSendContact = async (contactsToSend) => {
        if (!contactsToSend || contactsToSend.length === 0) return;

        const target = selectedUser || selectedGroup;
        if (!target) return;

        const token = localStorage.getItem('token');
        try {
            let contentPayload;
            if (contactsToSend.length === 1) {
                const contact = contactsToSend[0];
                contentPayload = JSON.stringify({
                    _id: contact._id,
                    name: contact.name,
                    mobile: contact.mobile,
                    image: contact.image,
                    about: contact.about
                });
            } else {
                contentPayload = JSON.stringify(contactsToSend.map(c => ({
                    _id: c._id,
                    name: c.name,
                    mobile: c.mobile,
                    image: c.image,
                    about: c.about
                })));
            }

            const formData = new FormData();
            formData.append('userId', user.id || user._id);
            formData.append('content', contentPayload);
            formData.append('type', 'contact');
            if (selectedUser) formData.append('toUserId', selectedUser._id);

            const endpoint = selectedGroup ? `/api/groups/${selectedGroup._id}/send` : '/api/chat/send';
            const res = await axios.post(endpoint, formData, {
                headers: { 'Authorization': `Bearer ${token}` }
            });

            const sentMsg = res.data.message;

            // Socket Emit
            if (selectedGroup) {
                setGroupMessages(prev => [...prev, sentMsg]);
                socket.emit('group_message', {
                    groupId: selectedGroup._id,
                    message: { ...sentMsg, sender_id: { _id: user.id || user._id, name: user.name } }
                });
            } else {
                setMessages(prev => [...prev, sentMsg]);
                socket.emit('send_message', {
                    _id: sentMsg._id,
                    sender_id: user.id || user._id,
                    receiverId: selectedUser._id,
                    content: sentMsg.content,
                    type: 'contact',
                    file_path: sentMsg.file_path
                });
            }

            setIsContactSelectionOpen(false);
            setIsConfirmContactSendOpen(false);
            setSelectedContacts([]);
            setSnackbar({ message: 'Contact(s) shared successfully', type: 'success', variant: 'system' });

            if (selectedGroup) fetchGroups(); else fetchUsers();
        } catch (err) {
            console.error('Failed to send contact:', err);
            setSnackbar({ message: 'Failed to share contacts', type: 'error' });
        }
    };

    const handleSendPoll = async () => {
        // Validate question
        if (!pollQuestion.trim()) {
            setSnackbar({ message: 'No question entered. Please enter the question to proceed forward', type: 'error', variant: 'system' });
            return;
        }

        // Filter valid options
        const validOptions = pollOptions.map(o => o.trim()).filter(o => o.length > 0);
        if (validOptions.length < 2) {
            setSnackbar({ message: 'Please enter at least 2 options', type: 'error', variant: 'system' });
            return;
        }

        // Check for duplicates
        const lowerOptions = validOptions.map(o => o.toLowerCase());
        const hasDup = lowerOptions.some((o, i) => lowerOptions.indexOf(o) !== i);
        if (hasDup) {
            setSnackbar({ message: 'Duplicate options are not allowed', type: 'error', variant: 'system' });
            return;
        }

        const target = selectedUser || selectedGroup;
        if (!target) return;

        const token = localStorage.getItem('token');
        try {
            let endpoint, payload;
            if (selectedGroup) {
                endpoint = '/api/groups/poll/send';
                payload = { groupId: selectedGroup._id, question: pollQuestion.trim(), options: validOptions, allowMultipleAnswers };
            } else {
                endpoint = '/api/chat/poll/send';
                payload = { toUserId: selectedUser._id, question: pollQuestion.trim(), options: validOptions, allowMultipleAnswers };
            }

            const res = await axios.post(endpoint, payload, {
                headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' }
            });

            const sentMsg = res.data.message;

            if (selectedGroup) {
                setGroupMessages(prev => [...prev, sentMsg]);
                socket.emit('group_message', {
                    groupId: selectedGroup._id,
                    message: { ...sentMsg, sender_id: { _id: user.id || user._id, name: user.name } }
                });
            } else {
                setMessages(prev => [...prev, sentMsg]);
                socket.emit('send_message', {
                    _id: sentMsg._id,
                    sender_id: user.id || user._id,
                    receiverId: selectedUser._id,
                    content: sentMsg.content,
                    type: 'poll',
                    poll: sentMsg.poll
                });
            }

            setIsPollModalOpen(false);
            setPollQuestion('');
            setPollOptions(['', '']);
            setAllowMultipleAnswers(true);
            setPollErrors({});
            setSnackbar({ message: 'Poll created!', type: 'success', variant: 'system' });
        } catch (err) {
            console.error('Poll send failed:', err);
            setSnackbar({ message: 'Failed to create poll', type: 'error', variant: 'system' });
        }
    };

    const handleVotePoll = async (msg, optionIndex) => {
        const isGroup = !!selectedGroup;
        const myId = String(user.id || user._id);
        const poll = msg.poll;
        if (!poll) return;

        const allowMultiple = poll.allowMultipleAnswers;

        // Determine current voted indexes
        const currentVotedIndexes = poll.options
            .map((opt, i) => ((opt.voters || []).some(v => String(v) === myId || String(v?._id || v) === myId) ? i : -1))
            .filter(i => i !== -1);

        let newIndexes;
        if (allowMultiple) {
            // Toggle this option
            if (currentVotedIndexes.includes(optionIndex)) {
                newIndexes = currentVotedIndexes.filter(i => i !== optionIndex);
            } else {
                newIndexes = [...currentVotedIndexes, optionIndex];
            }
        } else {
            // Single choice: toggle or switch
            if (currentVotedIndexes.includes(optionIndex)) {
                newIndexes = []; // Unvote
            } else {
                newIndexes = [optionIndex];
            }
        }

        const token = localStorage.getItem('token');
        const endpoint = isGroup ? `/api/groups/poll/${msg._id}/vote` : `/api/chat/poll/${msg._id}/vote`;

        try {
            const res = await axios.post(endpoint, { optionIndexes: newIndexes }, {
                headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' }
            });

            const updatedPoll = res.data.poll;
            const updateFn = prev => prev.map(m =>
                (String(m._id) === String(msg._id) || String(m.id) === String(msg._id))
                    ? { ...m, poll: updatedPoll }
                    : m
            );
            if (isGroup) setGroupMessages(updateFn);
            else setMessages(updateFn);
        } catch (err) {
            console.error('Vote failed:', err);
            setSnackbar({ message: 'Failed to vote', type: 'error', variant: 'system' });
        }
    };

    const handleSend = async (e, contentOverride = null, voiceFile = null, voiceDuration = null, voiceIsViewOnce = null) => {
        if (e) e.preventDefault();

        const textToSend = contentOverride !== null ? contentOverride : input;
        const targetFile = voiceFile || file;

        if ((!textToSend.trim() && !targetFile) || (!selectedUser && !selectedGroup)) return;

        // Optimistic UI Update (Temporary)
        const tempId = Date.now();

        const tempMsg = {
            id: tempId,
            sender_id: user.id || user._id,
            receiver_id: selectedUser ? selectedUser._id : null,
            group_id: selectedGroup ? selectedGroup._id : null,
            role: 'user',
            content: textToSend,
            type: voiceFile ? 'audio' : (file ? (file.type.startsWith('image/') ? 'image' : (file.type.startsWith('video/') ? 'video' : 'file')) : 'text'),
            file_path: targetFile ? URL.createObjectURL(targetFile) : null, // Local preview
            fileName: targetFile ? targetFile.name : null,
            fileSize: targetFile ? targetFile.size : null,
            duration: voiceDuration || null,
            pageCount: 1, // Default for optimistic UI
            created_at: new Date(),
            is_read: false,
            is_view_once: voiceFile ? (voiceIsViewOnce !== null ? voiceIsViewOnce : false) : false,
            reply_to: replyingTo // Store full object for rendering preview
        };

        if (selectedGroup) {
            setGroupMessages(prev => [...prev, { ...tempMsg, _id: tempId }]);
        } else {
            setMessages(prev => [...prev, { ...tempMsg, _id: tempId }]);
        }

        if (contentOverride !== null) {
            setGroupInput('');
        } else {
            setInput('');
        }
        setFile(null); // Clear file immediately from UI
        setReplyingTo(null); // Clear reply context immediately
        setTypingLinkPreview(null); // Clear typing preview immediately

        try {
            const formData = new FormData();
            formData.append('userId', user.id || user._id);
            if (selectedUser) formData.append('toUserId', selectedUser._id);

            // --- E2EE (Signal Protocol) Encryption ---
            let textToSubmit = textToSend;
            if (selectedUser) {
                try {
                    const encrypted = await SignalService.encrypt(selectedUser._id, textToSend);
                    formData.append('ciphertext', encrypted.body);
                    formData.append('session_header', JSON.stringify({
                        type: encrypted.type,
                        registrationId: encrypted.registrationId
                    }));
                    textToSubmit = ''; // DON'T send plaintext content to server
                } catch (e2eeErr) {
                    console.warn('[E2EE] Encryption failed, falling back to server-side encryption:', e2eeErr);
                }
            }
            // -----------------------------------------

            formData.append('content', textToSubmit);
            if (targetFile) formData.append('file', targetFile);
            if (tempMsg.reply_to) {
                formData.append('reply_to', tempMsg.reply_to._id);
            }
            if (tempMsg.is_view_once) {
                formData.append('is_view_once', true);
            }
            if (voiceDuration) {
                formData.append('duration', voiceDuration);
            }

            // Ensure socket is connected before potential emit
            if (!socket.connected) {
                console.warn('Socket disconnected. Attempting reconnect before send...');
                socket.connect();
            }

            // Upload to Server
            const token = localStorage.getItem('token');
            const endpoint = selectedGroup ? `/api/groups/${selectedGroup._id}/send` : '/api/chat/send';

            const res = await axios.post(endpoint, formData, {
                headers: {
                    'Authorization': `Bearer ${token}`
                }
            });

            if (res.data.status === 'pending_request') {
                setMessages(prev => prev.filter(m => m.id !== tempId));
                setSnackbar({ message: 'Message request sent. They must accept before you can continue.', type: 'info', variant: 'system' });
                fetchUsers();
                fetchMessageRequests();
                return;
            }

            const sentMsg = res.data.message;

            // UPDATE LOCAL STATE WITH REAL MESSAGE
            if (selectedGroup) {
                setGroupMessages(prev => prev.map(msg =>
                    msg._id === tempId ? { ...sentMsg, reply_to: tempMsg.reply_to } : msg
                ));

                // EMIT SOCKET FOR GROUP
                socket.emit('group_message', {
                    groupId: selectedGroup._id,
                    message: {
                        ...sentMsg,
                        sender_id: { _id: user.id || user._id, name: user.name }
                    }
                });

                fetchGroups(); // Refresh group lists for last message sync
            } else {
                setMessages(prev => prev.map(msg =>
                    msg._id === tempId ? { ...sentMsg, reply_to: tempMsg.reply_to } : msg
                ));

                // critically: EMIT SOCKET NOW with the REAL server file_path and reply context
                socket.emit('send_message', {
                    _id: sentMsg._id, // Pass server ID
                    sender_id: user.id || user._id,
                    receiverId: selectedUser._id,
                    content: sentMsg.content,
                    ciphertext: sentMsg.ciphertext,
                    session_header: sentMsg.session_header,
                    type: sentMsg.type,
                    file_path: sentMsg.file_path,
                    fileName: sentMsg.fileName,
                    is_view_once: sentMsg.is_view_once,
                    reply_to: tempMsg.reply_to // Pass full reply object if needed by client, or just ID
                });

                fetchUsers(); // Force refresh contact list from server
            }

        } catch (err) {
            console.error("Failed to send msg", err);

            // REMOVE OPTIMISTIC MESSAGE ON FAILURE
            if (selectedGroup) {
                setGroupMessages(prev => prev.filter(m => m.id !== tempId && m._id !== tempId));
            } else {
                setMessages(prev => prev.filter(m => m.id !== tempId && m._id !== tempId));
            }

            if (err.response && err.response.status === 403) {
                setSnackbar({ message: err.response.data.error || 'Permission denied', type: 'error' });
                fetchUsers(); // Refresh to catch status changes
            }
        }
    };

